mapper.select:
select la.id, la.phone, la.name, la.identification_number, la.lease_start_date, la.lease_end_date, la.rent, la.deposit, la.status, la.source_type, la.creator_type, la.auto_generated, la.create_time, ai.id as apartment_id, ai.name as apartment_name, ai.district_name, ai.city_name, ai.province_name, ri.id as room_id, ri.room_number, pt.id as payment_type_id, pt.name as payment_name, pt.pay_month_count, lt.id as lease_term_id, lt.month_count, lt.unit from lease_agreement la left join apartment_info ai on la.apartment_id = ai.id and ai.is_deleted = 0 left join room_info ri on la.room_id = ri.id and ri.is_deleted = 0 left join payment_type pt on la.payment_type_id = pt.id and pt.is_deleted = 0 left join lease_term lt on la.lease_term_id = lt.id and lt.is_deleted = 0 where la.is_deleted = 0 and la.creator_id = #{landlordId} and la.creator_type = 2
and la.status = #{status}
order by la.create_time desc

select COALESCE(SUM(la.rent), 0)
from lease_agreement la
where la.is_deleted = 0
  and la.creator_id = #{landlordId}
  and la.creator_type = 2
  and la.status = 2

      and la.lease_start_date >= #{startDate}


      and la.lease_start_date <= #{endDate}

select COALESCE(SUM(la.deposit), 0)
from lease_agreement la
where la.is_deleted = 0
  and la.creator_id = #{landlordId}
  and la.creator_type = 2
  and la.status = 2

      and la.lease_start_date >= #{startDate}


      and la.lease_start_date <= #{endDate}
